mapper.select:
SELECT FROM reservation r INNER JOIN property p ON p.id = r.property_id INNER JOIN tower tw ON tw.id = r.tower_id INNER JOIN unit_master u ON u.id = r.unit_id INNER JOIN customer c ON c.id = r.customer_id LEFT JOIN pm_lease l ON l.id = r.converted_lease_id WHERE r.is_deleted = FALSE
AND ( LOWER(r.reservation_number) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(p.property_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(c.customer_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(u.unit_code) LIKE CONCAT('%', LOWER(#{search}), '%') )
AND r.reservation_status = #{reservationStatus}
AND r.workflow_status = #{workflowStatus}
ORDER BY r.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM reservation r INNER JOIN property p ON p.id = r.property_id INNER JOIN unit_master u ON u.id = r.unit_id INNER JOIN customer c ON c.id = r.customer_id WHERE r.is_deleted = FALSE
AND ( LOWER(r.reservation_number) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(p.property_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(c.customer_name) LIKE CONCAT('%', LOWER(#{search}), '%') OR LOWER(u.unit_code) LIKE CONCAT('%', LOWER(#{search}), '%') )
AND r.reservation_status = #{reservationStatus}
AND r.workflow_status = #{workflowStatus}

mapper.insert:
INSERT INTO reservation (
    tenant_id, reservation_number, property_id, tower_id, unit_id, customer_id, reservation_status,
    workflow_status, payment_status, reservation_date, expiry_date, quoted_rent, currency,
    deposit_amount, created_by, notes
)
VALUES (
    1, #{reservationNumber}, #{propertyId}, #{towerId}, #{unitId}, #{customerId}, #{reservationStatus},
    #{workflowStatus}, #{paymentStatus}, #{reservationDate}, #{expiryDate}, #{quotedRent}, #{currency},
    #{depositAmount}, #{createdBy}, #{notes}
)

mapper.select:
SELECT COUNT(*)
FROM reservation
WHERE unit_id = #{unitId}
  AND is_deleted = FALSE
  AND reservation_status IN ('DRAFT', 'PENDING_PAYMENT', 'PENDING_APPROVAL', 'CONFIRMED')
  AND id != #{excludeId}
  AND reservation_date <= #{expiryDate}
  AND expiry_date >= #{reservationDate}

SELECT COUNT(*)
FROM pm_lease
WHERE unit_id = #{unitId}
  AND is_deleted = FALSE
  AND lease_status = 'ACTIVE'
  AND start_date <= #{endDate}
  AND end_date >= #{startDate}
